# fix_darkmode.ps1 - Modo oscuro/claro
Write-Host "Instalando modo oscuro/claro..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\components\Topbar.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/components/Topbar.tsx" -ForegroundColor Yellow

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\layouts\MainLayout.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/layouts/MainLayout.tsx" -ForegroundColor Yellow

Write-Host "Modo oscuro listo!" -ForegroundColor Green
